  DALI_TEST_CHECK(!color.HasColorId());
  DALI_TEST_EQUALS(color.GetColorId(), String(), TEST_LOCATION);

  Vector4 resolved = color.GetRgba();
  DALI_TEST_EQUALS(resolved, Vector4::ZERO, TEST_LOCATION);

  END_TEST;
}

